echo '
<div style="margin: 15px 0; text-align: center;">
  <input type="text" id="searchMadrasah" placeholder="Cari Nama Madrasah..."
         style="padding: 8px 12px; width: 320px; border: 1px solid #ccc; border-radius: 6px; font-size: 14px;" 
         onkeyup="autoSearchMadrasah()" />
</div>

<div id="resetSearchContainer" style="display: none; margin-top: 10px; text-align: center;">
  <button onclick="resetSearch()" 
          style="padding: 8px 16px; background-color: #dc3545; color: white; border: none; border-radius: 6px; cursor: pointer;">
    🔄 Batalkan Cari / Kembali
  </button>
</div>

<script>
let searchTimeout;

function autoSearchMadrasah() {
  clearTimeout(searchTimeout);
  searchTimeout = setTimeout(function() {
    const keyword = document.getElementById("searchMadrasah").value.trim();
    if (keyword !== "") {
      // Target file profil_list.php
      window.location.href = "profil_list.php?q=(nama%20satker~contains~" + encodeURIComponent(keyword) + ")";
    }
  }, 800); // Jeda waktu ketik
}

function resetSearch() {
  window.location.href = "profil_list.php";
}

// Cek apakah sedang dalam kondisi pencarian
window.addEventListener("DOMContentLoaded", function() {
  const params = new URLSearchParams(window.location.search);
  if (params.has("q")) {
    document.getElementById("resetSearchContainer").style.display = "block";
  }
});
</script>
';
